const DatePickerField = forwardRef<
  ComponentRef<typeof DatePickerPrimitive.Control>,
  DatePickerFieldProps
>(function DatePickerField(
  {
    clearLabel = 'Clear date',
    clearTriggerProps,
    inputProps,
    placeholder = 'Select date',
    triggerLabel = 'Open calendar',
    triggerProps,
    ...props
