@layer moduix.components {
  @keyframes date-picker-content-open {
    from {
      opacity: var(
        --moduix-date-picker-content-closed-opacity,
        var(--moduix-popup-motion-starting-opacity, 0)
      );
      translate: var(--moduix-popup-motion-starting-translate-x, 0)
        var(--moduix-popup-motion-starting-translate-y, 0);
      transform: scale(
        var(
          --moduix-date-picker-content-closed-scale,
          var(--moduix-popup-motion-starting-scale, var(--moduix-scale-popup))
        )
      );
    }

    to {
      opacity: 1;
      translate: 0 0;
      transform: scale(1);
    }
  }

  @keyframes date-picker-content-closed {
    from {
      opacity: 1;
      translate: 0 0;
      transform: scale(1);
    }

    to {
      opacity: var(
        --moduix-date-picker-content-closed-opacity,
        var(--moduix-popup-motion-ending-opacity, 0)
      );
      translate: var(--moduix-popup-motion-ending-translate-x, 0)
        var(--moduix-popup-motion-ending-translate-y, 0);
      transform: scale(
        var(
          --moduix-date-picker-content-closed-scale,
          var(--moduix-popup-motion-ending-scale, var(--moduix-scale-popup))
        )
      );
    }
  }

  .root {
    box-sizing: border-box;
    display: inline-flex;
    width: var(--moduix-date-picker-width, 18.75rem);
    max-width: var(--moduix-date-picker-max-width, 100%);
    flex-direction: column;
    align-items: flex-start;
    gap: var(--moduix-date-picker-root-gap, var(--moduix-spacing-1));
    color: var(--moduix-date-picker-color, var(--moduix-color-foreground));

    &:is([data-disabled], [data-readonly]) {
      opacity: var(--moduix-date-picker-disabled-opacity, var(--moduix-opacity-disabled));
    }
  }

  .label {
    display: inline-flex;
    align-items: center;
    color: var(
      --moduix-date-picker-label-color,
      var(--moduix-date-picker-color, var(--moduix-color-foreground))
    );
    font-size: var(--moduix-date-picker-label-font-size, var(--moduix-text-sm));
    font-weight: var(--moduix-date-picker-label-font-weight, var(--moduix-weight-medium));
    line-height: var(--moduix-date-picker-label-line-height, var(--moduix-line-height-text-sm));
    user-select: none;
  }

  .control {
    position: relative;
    display: flex;
    width: 100%;
    min-width: 0;
    align-items: center;
    gap: var(--moduix-date-picker-input-gap, var(--moduix-spacing-2));
    color: var(--moduix-date-picker-color, var(--moduix-color-foreground));
  }

  .input {
    box-sizing: border-box;
    flex: 1 1 0;
    width: 100%;
    min-width: min(var(--moduix-date-picker-input-min-width, 7.5rem), 100%);
    height: var(--moduix-date-picker-control-height, var(--moduix-size-md));
    margin: 0;
    border: var(--moduix-date-picker-border-width, var(--moduix-border-width-sm)) solid
      var(--moduix-date-picker-border-color, var(--moduix-color-border));
    border-radius: var(--moduix-date-picker-radius, var(--moduix-radius-md));
    padding-block: var(--moduix-date-picker-input-padding-y, var(--moduix-spacing-1));
    padding-inline: var(--moduix-date-picker-input-padding-x-start, var(--moduix-spacing-3-5))
      var(--moduix-date-picker-input-padding-x-end, 4.25rem);
    background-color: var(--moduix-date-picker-bg, var(--moduix-color-background));
    color: inherit;
    font: inherit;
    font-size: var(--moduix-date-picker-font-size, var(--moduix-text-md));
    line-height: var(--moduix-date-picker-line-height, var(--moduix-line-height-text-md));
    outline: var(
        --moduix-date-picker-focus-ring-width,
        var(--moduix-focus-ring-inset-width, var(--moduix-border-width-sm))
      )
      solid transparent;
    outline-offset: calc(
      var(
          --moduix-date-picker-focus-ring-width,
          var(--moduix-focus-ring-inset-width, var(--moduix-border-width-sm))
        ) *
        -1
    );
    transition:
      background-color var(--moduix-date-picker-transition, var(--moduix-transition-default)),
      border-color var(--moduix-date-picker-transition, var(--moduix-transition-default)),
      color var(--moduix-date-picker-transition, var(--moduix-transition-default)),
      outline-color var(--moduix-date-picker-transition, var(--moduix-transition-default)),
      opacity var(--moduix-date-picker-transition, var(--moduix-transition-default));

    &::placeholder {
      color: var(--moduix-date-picker-placeholder-color, var(--moduix-color-muted-foreground));
      opacity: 1;
    }

    &:focus,
    .control[data-focus] & {
      border-color: var(--moduix-date-picker-focus-ring-color, var(--moduix-color-ring));
      outline-color: var(--moduix-date-picker-focus-ring-color, var(--moduix-color-ring));
    }

    &:is([data-invalid], [aria-invalid='true']),
    .control[data-invalid] & {
