    justify-content: center;
    margin: 0;
    border: 0;
    border-radius: var(--moduix-date-picker-action-radius, var(--moduix-radius-sm));
    padding: 0;
    background: var(--moduix-date-picker-action-bg, transparent);
    color: var(--moduix-date-picker-icon-color, var(--moduix-color-muted-foreground));
    font: inherit;
    line-height: 0;
    outline: var(
        --moduix-date-picker-action-focus-ring-width,
        var(--moduix-focus-ring-inset-width, var(--moduix-border-width-sm))
      )
      solid transparent;
    outline-offset: var(--moduix-date-picker-action-focus-ring-offset, 0);
    cursor: pointer;
    transition:
      background-color var(--moduix-date-picker-transition, var(--moduix-transition-default)),
      color var(--moduix-date-picker-transition, var(--moduix-transition-default)),
      outline-color var(--moduix-date-picker-transition, var(--moduix-transition-default)),
