      opacity: var(--moduix-date-picker-disabled-opacity, var(--moduix-opacity-disabled));
    }

    &[hidden] {
      display: none;
    }

    &:not(:is([disabled], [data-disabled])) {
      @media (hover: hover) {
        &:hover {
          background-color: var(--moduix-date-picker-action-bg-hover, var(--moduix-color-muted));
          color: var(--moduix-date-picker-action-color-hover, var(--moduix-color-foreground));
