    height: var(--moduix-date-picker-action-size, var(--moduix-size-xs));
    transform: translateY(-50%);
  }

  .trigger {
    inset-inline-end: var(--moduix-date-picker-trigger-offset-right, var(--moduix-spacing-2));
  }

  .clearTrigger {
