    border-radius: var(--moduix-date-picker-table-cell-radius, var(--moduix-radius-sm));
    padding: 0;
    background: var(--moduix-date-picker-table-cell-bg, transparent);
    color: var(
      --moduix-date-picker-table-cell-color,
      var(--moduix-date-picker-content-color, var(--moduix-color-foreground))
